pr_description:
A new plugin, for NodeJS developers, that generates SKD for `graphql-request` based on schema and operations. 

Usage example:

```yml
schema: https://countries.trevorblades.com/
documents: 'src/graphql/**/*.graphql'
generates:
  src/sdk.ts:
    plugins:
      - typescript
      - typescript-operations
      - typescript-graphql-request
```

```graphql
query continents {
  continents {
    name
    countries {
      ...CountryFields
    }
  }
}
fragment CountryFields on Country {
  name
  currency
}
```

And then to use the SDK:

```ts
import { GraphQLClient } from 'graphql-request';
import { getSdk } from './sdk'; // THIS FILE IS GENERATED

async function main() {
  const client = new GraphQLClient('https://countries.trevorblades.com/');
  const sdk = getSdk(client);
  const { continents } = await sdk.continents(); // This is fully typed, based on the query
  
  console.log(`GraphQL data:`, continents);
}

main().catch(e => {
  console.error(e);
});

```

An example repo could be found here: 
https://github.com/dotansimha/graphql-codegen-graphql-request-example

diff_text:
diff --git a/packages/plugins/typescript/graphql-request/tests/graphql-request.spec.ts b/packages/plugins/typescript/graphql-request/tests/graphql-request.spec.ts
new file mode 100644
index 0000000..c323a02
--- /dev/null
+++ b/packages/plugins/typescript/graphql-request/tests/graphql-request.spec.ts
@@ -0,0 +1,81 @@
+import { compileTs } from '@graphql-codegen/testing';
+import { plugin } from '../src/index';
+import { parse, buildClientSchema } from 'graphql';
+import { Types, mergeOutputs } from '@graphql-codegen/plugin-helpers';
+import { plugin as tsPlugin } from '@graphql-codegen/typescript';
+import { plugin as tsDocumentsPlugin } from '@graphql-codegen/typescript-operations';
+import { readFileSync } from 'fs';
+
+describe('graphql-request', () => {
+  const schema = buildClientSchema(JSON.parse(readFileSync('../../../../dev-test/githunt/schema.json').toString()));
+  const basicDoc = parse(/* GraphQL */ `
+    query feed {
+      feed {
+        id
+        commentCount
+        repository {
+          owner {
+            avatar_url
+          }
+        }
+      }
+    }
+
+    query feed2($v: String!) {
+      feed {
+        id
+      }
+    }
+
+    query feed3($v: String) {
+      feed {
+        id
+      }
+    }
+
+    query feed4($v: String! = "TEST") {
+      feed {
+        id
+      }
+    }
+  `);
+
+  const validateAndCompile = async (content: Types.PluginOutput, config, docs, pluginSchema, usage = '') => {
+    const m = mergeOutputs([await tsPlugin(pluginSchema, docs, config, { outputFile: '' }), await tsDocumentsPlugin(pluginSchema, docs, config, { outputFile: '' }), content, usage]);
+
+    await compileTs(m);
+
+    return m;
+  };
+
+  describe('sdk', () => {
+    it('Should generate a correct wrap method', async () => {
+      const config = {};
+      const docs = [{ filePath: '', content: basicDoc }];
+      const result = (await plugin(schema, docs, config, {
+        outputFile: 'graphql.ts',
+      })) as Types.ComplexPluginOutput;
+
+      const usage = `
+async function test() {
+  const client = new GraphQLClient('');
+  const sdk = getSdk(client);
+  
+  await sdk.feed();
+  await sdk.feed3();
+  await sdk.feed4();
+
+  const result = await sdk.feed2({ v: "1" });
+
+  if (result.feed) {
+    if (result.feed[0]) {
+      const id = result.feed[0].id
+    }
+  }
+}`;
+      const output = await validateAndCompile(result, config, docs, schema, usage);
+
+      expect(output).toMatchSnapshot();
+    });
+  });
+});

