pr_description:
When generating flow operations, the `useFlowReadOnlyTypes:true` flag was not working when `preResolveTypes:true`. This diff updates the `FlowDocumentsVisitor` logic to insert the read-only modifier when formatting the name field so that it's consistent across processors. It also updates the `wrapArray` logic to use `$ReadOnlyArray` when `useFlowReadOnlyTypes:true`.

Output from live demo:

**schema.graphql**
<pre lang="graphql">
scalar Date

schema {
  query: Query
}

type Query {
  user(id: ID!): User
  allUsers: [User]
}

enum Role {
  USER,
  ADMIN,
}

interface Node {
  id: ID!
}

type User implements Node {
  id: ID!
  username: String!
  email: String!
  role: Role!
  friends: [Friend!]!
}

type Friend implements Node {
  id: ID!
  name: String!
}
</pre>

**operation.graphql**
<pre lang="graphql">
query findUser($userId: ID!) {
  user(id: $userId) {
    ...UserFields
    friends {
        ...FriendFields
    }
  }
}

fragment UserFields on User {
  id
  username
  role
}

fragment FriendFields on Friend {
    id
    name
}
</pre>

**codegen.yml**
<pre lang="yaml">
generates:
  types.flow.js:
    plugins:
      - flow
      - flow-operations
    config:
      preResolveTypes: true
      useFlowReadOnlyTypes: true
</pre>

**types.flow.js**
<table>
  <thead>
    <tr>
      <td>Before</td>
      <td>After</td>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>
<pre lang="js">
// @flow 


// @flow 

/** All built-in and custom scalars, mapped to their actual values */
export type Scalars = {|
  ID: string,
  String: string,
  Boolean: boolean,
  Int: number,
  Float: number,
  Date: any,
|};


export type Query = {|
  __typename?: 'Query',
  +user?: ?User,
  +allUsers?: ?Array<?User>,
|};


export type QueryUserArgs = {|
  id: $ElementType<Scalars, 'ID'>,
|};

export const RoleValues = Object.freeze({
  User: 'USER', 
  Admin: 'ADMIN'
});


export type Role = $Values<typeof RoleValues>;

export type Node = {|
  +id: $ElementType<Scalars, 'ID'>,
|};

export type User = {|
  ...Node,
  ...{|
    __typename?: 'User',
    +id: $ElementType<Scalars, 'ID'>,
    +username: $ElementType<Scalars, 'String'>,
    +email: $ElementType<Scalars, 'String'>,
    +role: Role,
    +friends: Array<Friend>,
  |}
|};

export type Friend = {|
  ...Node,
  ...{|
    __typename?: 'Friend',
    +id: $ElementType<Scalars, 'ID'>,
    +name: $ElementType<Scalars, 'String'>,
  |}
|};


export type FindUserQueryVariables = {
  userId: $ElementType<Scalars, 'ID'>,
};


export type FindUserQuery = { __typename?: 'Query', user?: ?(
    { __typename?: 'User', friends: Array<(
      { __typename?: 'Friend' }
      & FriendFieldsFragment
    )> }
    & UserFieldsFragment
  ) };

export type UserFieldsFragment = { __typename?: 'User', id: string, username: string, role: Role };

export type FriendFieldsFragment = { __typename?: 'Friend', id: string, name: string };

</pre>
      </td>
      <td>
<pre lang="js">
// @flow 


// @flow 

/** All built-in and custom scalars, mapped to their actual values */
export type Scalars = {|
  ID: string,
  String: string,
  Boolean: boolean,
  Int: number,
  Float: number,
  Date: any,
|};


export type Friend = {|
  ...Node,
  ...{|
    __typename?: 'Friend',
    +id: $ElementType<Scalars, 'ID'>,
    +name: $ElementType<Scalars, 'String'>,
  |}
|};

export type Node = {|
  +id: $ElementType<Scalars, 'ID'>,
|};

export type Query = {|
  __typename?: 'Query',
  +user?: ?User,
