diff --git a/packages/plugins/typescript/urql-graphcache/tests/urql.spec.ts b/packages/plugins/typescript/urql-graphcache/tests/urql.spec.ts
new file mode 100644
index 0000000..cecc3b8
--- /dev/null
+++ b/packages/plugins/typescript/urql-graphcache/tests/urql.spec.ts
@@ -0,0 +1,30 @@
+import { parse, buildClientSchema } from 'graphql';
+
+describe('urql', () => {
+  let spyConsoleError: jest.SpyInstance;
+  beforeEach(() => {
+    spyConsoleError = jest.spyOn(console, 'warn');
+    spyConsoleError.mockImplementation();
+  });
+
+  afterEach(() => {
+    spyConsoleError.mockRestore();
+  });
+
+  const schema = buildClientSchema(require('../../../../../dev-test/githunt/schema.json'));
+  const basicDoc = parse(/* GraphQL */ `
+    query test {
+      feed {
+        id
+        commentCount
+        repository {
+          full_name
+          html_url
+          owner {
+            avatar_url
+          }
+        }
+      }
+    }
+  `);
+});

